// src/nodes/llmNode.js
import { Handle, Position } from 'reactflow';
import './node.css';

export const LLMNode = ({ id, data }) => {
  return (
    <div className="vs-node">
      <div className="vs-node-header">{data?.label || "LLM"}</div>
      <div style={{ marginTop: '8px', color: '#d1d5db' }}>
        This is an LLM node
      </div>
      <Handle
        type="target"
        position={Position.Left}
        id="system"
        style={{ top: '30%' }}
      />
      <Handle
        type="target"
        position={Position.Left}
        id="prompt"
        style={{ top: '70%' }}
      />
      <Handle
        type="source"
        position={Position.Right}
        id="response"
      />
    </div>
  );
};
